// 1. Setup Time and Local Variables
const timeSettings = { timeZone: 'Asia/Kuala_Lumpur', hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' };
const currentTime = new Date().toLocaleTimeString("en-GB", timeSettings);
const currentTimestamp = Date.now();
let payloadStr = msg.payload.toString().trim().toLowerCase();

let logData = null;

// 2. LOGIC: Parking Stay Duration
if (msg.topic && msg.topic.includes("parking/slot/")) {
    let slotNum = msg.topic.split('/').pop();

    if (payloadStr === "occupied" || payloadStr === "1") {
        flow.set("slot" + slotNum + "_arrivalTime", currentTime);
        flow.set("slot" + slotNum + "_startTS", currentTimestamp);
        node.status({ fill: "blue", shape: "dot", text: "Slot " + slotNum + " Occupied" });
        return null;
    }
    else if (payloadStr === "empty" || payloadStr === "0") {
        let startTime = flow.get("slot" + slotNum + "_arrivalTime");
        let startTS = flow.get("slot" + slotNum + "_startTS");

        let remarkText = "";

        if (startTime && startTS) {
            let durationMs = currentTimestamp - startTS;
            let mins = Math.floor(durationMs / 60000);
            let secs = Math.floor((durationMs % 60000) / 1000);
            remarkText = "Stayed: " + mins + "m " + secs + "s";
        } else {
            remarkText = "<span style='color: #f39c12;'>Time lost (System Deploy)</span>";
        }

        // ★ NEW: Assign a specific color to each slot! ★
        let slotColor = "#333333"; // Default dark grey
        if (slotNum === "1") slotColor = "#3498db"; // Blue
        else if (slotNum === "2") slotColor = "#9b59b6"; // Purple
        else if (slotNum === "3") slotColor = "#e67e22"; // Orange

        // Generate data WITH HTML styling for the Location
        logData = {
            "Time": currentTime,
            "Location": "<span style='color: " + slotColor + "; font-weight: bold;'>Slot " + slotNum + "</span>",
            "Status": "<span style='color: #27ae60; font-weight: bold;'>COMPLETED</span>",
            "Remark": remarkText
        };

        flow.set("slot" + slotNum + "_arrivalTime", null);
        flow.set("slot" + slotNum + "_startTS", null);
        node.status({ fill: "green", shape: "ring", text: "Parking session logged" });
    }
}

// 3. LOGIC: Fire and Panic Alarms
else if (msg.topic && msg.topic.includes("alarm/status")) {
    if (payloadStr === "smoke" || payloadStr === "panic") {

        let alertColor = payloadStr === "smoke" ? "#e74c3c" : "#8e44ad";
        let icon = payloadStr === "smoke" ? "🔥" : "⚠️";

        // Generate data WITH HTML styling
        logData = {
            "Time": currentTime,
            "Location": "<span style='color: #c0392b; font-weight: bold;'>🚨 Emergency System</span>",
            "Status": "<span style='color: " + alertColor + "; font-weight: bold;'>" + payloadStr.toUpperCase() + " ALERT</span>",
            "Remark": icon + " " + (payloadStr === "smoke" ? "Fire detected in lot!" : "Manual panic button pressed!")
        };

        node.status({ fill: "red", shape: "dot", text: "Alarm Logged" });
    }
}

// 4. SEND DATA 
if (logData !== null) {

    let history = flow.get("dashboardTableHistory") || [];
    history.unshift(logData);

    if (history.length > 15) {
        history.pop();
    }

    flow.set("dashboardTableHistory", history);

    // ★ 核心终极修复：深度克隆 (Deep Clone) ★
    // 这行代码会把数据彻底粉碎并重新生成一个全新的包裹。
    // Node-RED 会认为这是 100% 毫无关联的新数据，从而立刻、瞬间推送到你的屏幕上！
    let clonedHistory = JSON.parse(JSON.stringify(history));

    let msgTable = { payload: clonedHistory };
    let msgFirebase = { payload: logData };

    return [msgTable, msgFirebase];
}

return null;
